class Solution {
public:
    bool equalFrequency(string word) {
        for (int i = 0; i < word.size(); i++) {
            string temp = word;
            temp.erase(i, 1);
            unordered_map<char, int> count;
            for (char c : temp) {
                count[c]++;
            }
            set<int> uniqueCounts;
            for (auto& pair : count) {
                uniqueCounts.insert(pair.second);
            }
            if (uniqueCounts.size() == 1) {
                return true;
            }
        }
        return false;
    }
};
